const input = $input.first().json;

const driveId = input.DriveId;
const folderId = input.FolderId;
const previous = input.Previous ?? {};

const priorDeltaLink = previous.deltaLink ?? null;
const priorItems = Array.isArray(previous.items) ? previous.items : [];

if (!driveId) {
  throw new Error('Missing DriveId');
}

if (!folderId) {
  throw new Error('Missing FolderId');
}

const initialUrl = `https://graph.microsoft.com/v1.0/drives/${driveId}/items/${folderId}/delta?$select=id,name,size,webUrl,file,folder,createdDateTime,lastModifiedDateTime,parentReference,deleted`;

return [
  {
    json: {
      driveId,
      folderId,
      initialUrl,
      nextUrl: priorDeltaLink || initialUrl,
      deltaLink: priorDeltaLink,
      allItems: priorItems,
      rootPath: previous.rootPath ?? null,
      isIncremental: !!priorDeltaLink
    }
  }
];

const input = $input.first().json;

const existing = Array.isArray(input.allItems) ? input.allItems : [];
const pageItems = Array.isArray(input.value) ? input.value : [];

const byId = new Map(existing.map(item => [item.id, item]));

let rootPath = input.rootPath ?? null;

// Try to detect rootPath if not already known
if (!rootPath && pageItems.length > 0) {
  const candidate = pageItems[0]?.parentReference?.path;
  if (candidate && candidate.includes('/drive/root:')) {
    rootPath = candidate.replace('/drive/root:', '');
  }
}

for (const item of pageItems) {
  if (item.deleted) {
    byId.delete(item.id);
    continue;
  }

  const fullParentPathRaw = item.parentReference?.path ?? '';
  const fullParentPath = fullParentPathRaw.replace('/drive/root:', '');

  let relativePath = fullParentPath;

  if (rootPath && relativePath.startsWith(rootPath)) {
    relativePath = relativePath.slice(rootPath.length);
  }

  if (relativePath.startsWith('/')) {
    relativePath = relativePath.slice(1);
  }

  const fullRelativePath = relativePath
    ? `${relativePath}/${item.name}`
    : item.name;

  byId.set(item.id, {
    id: item.id,
    name: item.name,
    isFile: !!item.file,
    isFolder: !!item.folder,
    isDeleted: false,
    size: item.size ?? null,
    webUrl: item.webUrl ?? '',
    lastModifiedDateTime: item.lastModifiedDateTime ?? null,
    createdDateTime: item.createdDateTime ?? null,
    parentPath: fullParentPath,
    relativePath,
    fullRelativePath
  });
}

return [
  {
    json: {
      driveId: input.driveId,
      folderId: input.folderId,
      initialUrl: input.initialUrl,
      nextUrl: input['@odata.nextLink'] ?? null,
      deltaLink: input['@odata.deltaLink'] ?? input.deltaLink ?? null,
      rootPath,
      allItems: Array.from(byId.values()),
      isIncremental: input.isIncremental ?? false
    }
  }
];

const input = $input.first().json;

return [
  {
    json: {
      count: Array.isArray(input.allItems) ? input.allItems.length : 0,
      deltaLink: input.deltaLink ?? null,
      rootPath: input.rootPath ?? null,
      isIncremental: input.isIncremental ?? false,
      items: input.allItems ?? []
    }
  }
];

